// @ts-check

import { AbstractHandler } from './AbstractHandler.js'
import { Command } from '../../utils/Command.js'
import { CommandType } from '../../utils/CommandType.js'
import { TypesHandler } from '../../utils/TypesHandler.js'
import { RuntimeName } from '../../utils/RuntimeName.js'
import { GetInstanceFieldHandler } from './GetInstanceFieldHandler.js'

/**
 * @typedef {import('../../utils/Command.js').Command} CommandModel
 */

class PassByValueHandler extends AbstractHandler {
    requiredParametersCount = 1

    /**
     * @param {CommandModel} command
     * @returns {unknown}
     */
    process(command) {
        this.validate(command, this.requiredParametersCount, this.constructor.name)
        const instance = command.payload[0]
        return this.projectValue(instance)
    }

    /**
     * @param {unknown} value
     * @returns {unknown}
     */
    projectValue(value) {
        if (TypesHandler.isPrimitiveOrNullOrUndefined(value)) {
            return value
        }

        if (Array.isArray(value)) {
            const elements = new Array(value.length)
            for (let i = 0; i < value.length; i++) {
                elements[i] = this.projectValue(value[i])
            }

            return new Command(RuntimeName.Nodejs, CommandType.Array, elements)
        }

        return this.projectObject(value)
    }

    /**
     * @param {any} instance
     * @returns {Command}
     */
    projectObject(instance) {
        const typeName = instance?.constructor?.name ?? 'Object'
        const propertyNames = Object.keys(instance ?? {})

        const getTypeCommand = new Command(RuntimeName.Nodejs, CommandType.GetType, [typeName])
        let currentChain = new Command(RuntimeName.Nodejs, CommandType.CreateClassInstance, [getTypeCommand])

        const getInstanceFieldHandler = new GetInstanceFieldHandler()
        for (let i = 0; i < propertyNames.length; i++) {
            const propertyName = propertyNames[i]
            const propertyValue = getInstanceFieldHandler.process(
                new Command(RuntimeName.Nodejs, CommandType.GetInstanceField, [instance, propertyName])
            )
            const projectedValue = this.projectValue(propertyValue)

            currentChain = new Command(RuntimeName.Nodejs, CommandType.SetInstanceField, [
                currentChain,
                propertyName,
                projectedValue,
            ])
        }

        return currentChain
    }
}

export { PassByValueHandler }
